pipeline {
    agent any
    
    parameters {
        string(name: 'BUILD_COMMAND', defaultValue: '', description: 'The build command to execute')
        string(name: 'TEST_SCRIPT', defaultValue: '', description: 'The test script to run')
        string(name: 'DEPLOYMENT_STEPS', defaultValue: '', description: 'The deployment steps to perform')
    }
    
    stages {
        stage('Build') {
            steps {
                sh "${params.BUILD_COMMAND}"
            }
        }
        
        stage('Test') {
            steps {
                sh "${params.TEST_SCRIPT}"
            }
        }
        
        stage('Deploy') {
            steps {
                sh "${params.DEPLOYMENT_STEPS}"
            }
        }
    }
}